def _check_cache(con, fingerprint: str, force: bool) -> tuple[bool, bool, set[str]]:
    all_chunk_ids: set[str] = {
        row[0] for row in con.execute("SELECT chunk_id FROM embeddings").fetchall()
    }
    processed_ids: set[str] = {
        row[0] for row in con.execute("SELECT DISTINCT chunk_id FROM chunk_entities").fetchall()
    }
    cached = con.execute(
        "SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", [fingerprint]
    ).fetchone()

    config_match = cached is not None
    new_chunk_ids = all_chunk_ids - processed_ids

    if force:
        return False, False, set()
    if config_match and not new_chunk_ids:
        return True, False, set()
    if config_match and new_chunk_ids:
        return False, True, processed_ids
    return False, False, set()

func checkCache(con *sql.DB, fingerprint string, force bool) (bool, bool, map[string]struct{}, error) {
	allChunkRows, err := con.Query("SELECT chunk_id FROM embeddings")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query embeddings: %w", err)
	}
	defer allChunkRows.Close()
	allChunkIDs := make(map[string]struct{})
	for allChunkRows.Next() {
		var cid string
		if err := allChunkRows.Scan(&cid); err != nil {
			return false, false, nil, fmt.Errorf("checkCache: scan embeddings: %w", err)
		}
		allChunkIDs[cid] = struct{}{}
	}

	processedRows, err := con.Query("SELECT DISTINCT chunk_id FROM chunk_entities")
	if err != nil {
		return false, false, nil, fmt.Errorf("checkCache: query chunk_entities: %w", err)
	}
	defer processedRows.Close()
	processedIDs := make(map[string]struct{})
	for processedRows.Next() {
		var cid string
		if err := processedRows.Scan(&cid); err != nil {
			return false, false, nil, fmt.Errorf("checkCache: scan chunk_entities: %w", err)
		}
		processedIDs[cid] = struct{}{}
	}

	var cachedCount *int
	row := con.QueryRow("SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", fingerprint)
	var cnt int
	if err := row.Scan(&cnt); err == nil {
		cachedCount = &cnt
	}

	configMatch := cachedCount != nil
	newChunkIDs := make(map[string]struct{})
	for id := range allChunkIDs {
		if _, ok := processedIDs[id]; !ok {
			newChunkIDs[id] = struct{}{}
		}
	}

	if force {
		return false, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) == 0 {
		return true, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) > 0 {
		return false, true, processedIDs, nil
	}
	return false, false, make(map[string]struct{}), nil
}

