def match(self, text: str) -> list[EntityMatch]:
    vocab_hits: list[EntityMatch] = []

    if self._db_enrich:
        vocab_hits.extend(self._get_schema_matcher().match(text))

    if self._builder.data_term_count():
        vocab_hits.extend(self._get_data_matcher().match(text))

    spacy_hits: list[EntityMatch] = []
    if self._spacy_entities:
        spacy_hits = self._get_spacy_matcher().match(text)

    if vocab_hits and spacy_hits:
        return merge_matches(vocab_hits, spacy_hits, source_text=text)
    return vocab_hits or spacy_hits

func (p *NerPipeline) Match(text string) ([]EntityMatch, error) {
	var vocabHits []EntityMatch

	if p.dbEnrich {
		sm, err := p.getSchemaMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_schema_matcher: %w", err)
		}
		vocabHits = append(vocabHits, sm.Match(text)...)
	}

	if p.builder.DataTermCount() > 0 {
		dm, err := p.getDataMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_data_matcher: %w", err)
		}
		vocabHits = append(vocabHits, dm.Match(text)...)
	}

	var spacyHits []EntityMatch
	if p.spacyEntities {
		spm, err := p.getSpacyMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_spacy_matcher: %w", err)
		}
		spacyHits = spm.Match(text)
	}

	if len(vocabHits) > 0 && len(spacyHits) > 0 {
		return mergeMatches(vocabHits, spacyHits, text, true)
	}
	if len(vocabHits) > 0 {
		return vocabHits, nil
	}
	return spacyHits, nil
}

Translate the Python method `NerPipeline.run_on_chunks` to Go. Apply R01 (class -> struct + pointer receiver), R05 (dict -> map, list -> []T), R06 (None -> nil), R08 (f-string -> fmt.Sprintf), R10 (enumerate -> for i, x := range xs), R11 (Python truthiness -> explicit checks).

def run_on_chunks(
    self,
    chunks: list,
    entity_index: EntityIndex,
    chunk_ids: list[str] | None = None,
) -> dict[str, list[EntityMatch]]:
    results: dict[str, list[EntityMatch]] = {}
    for i, chunk in enumerate(chunks):
        cid = (
            chunk_ids[i]
            if chunk_ids is not None
            else (f"{chunk.document_name}:{chunk.chunk_index}")
        )
        content = chunk.content or ""
        matches = self.match(content)
        if matches:
            entity_index.index_chunk(cid, content, matches)
            results[cid] = matches
    return results

func (p *NerPipeline) RunOnChunks(chunks []DocumentChunk, entityIndex *EntityIndex, chunkIDs []string) (map[string][]EntityMatch, error) {
	results := make(map[string][]EntityMatch)
	for i, chunk := range chunks {
		var cid string
		if chunkIDs != nil {
			cid = chunkIDs[i]
		} else {
			cid = fmt.Sprintf("%s:%d", chunk.DocumentName, chunk.ChunkIndex)
		}
		content := chunk.Content
		if len(content) == 0 {
			content = ""
		}
		matches, err := p.Match(content)
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.RunOnChunks: match chunk %s: %w", cid, err)
		}
		if len(matches) > 0 {
			entityIndex.IndexChunk(cid, content, matches)
			results[cid] = matches
		}
	}
	return results, nil
}

