def _strip_span(text: str, start: int, end: int) -> tuple[int, int] | None:
    span_text = text[start:end]
    # Strip from left
    new_start = start
    for ch in span_text:
        if ch in _BOUNDARY_CHARS or ch.isspace():
            new_start += 1
        else:
            break
    # Strip from right
    new_end = end
    for ch in reversed(text[new_start:end]):
        if ch in _BOUNDARY_CHARS or ch.isspace():
            new_end -= 1
        else:
            break
    if new_end <= new_start:
        return None
    return new_start, new_end

func stripSpan(text string, start, end int) ([2]int, bool) {
	runes := []rune(text)
	if start < 0 || end > len(runes) || start >= end {
		return [2]int{}, false
	}

	// Strip from left
	newStart := start
	for newStart < end {
		ch := runes[newStart]
		if isBoundaryChar(ch) || unicode.IsSpace(ch) {
			newStart++
		} else {
			break
		}
	}

	// Strip from right
