		sourceDetailStr    *string
		sourceID           *string
		domainID           *string
		sessionFingerprint *string
		vec                []float32
	}

	records := make([]record, 0, len(chunks))
	for i, chunk := range chunks {
		embedContent := chunk.Content
		if chunk.EmbeddingContent != "" {
			embedContent = chunk.EmbeddingContent
		}
		chunkID := GenerateChunkID(chunk.DocumentName, chunk.ChunkIndex, embedContent)
