			sourceOffset:       chunk.SourceOffset,
			sourceLength:       chunk.SourceLength,
			namespace:          namespace,
			sourceDetailStr:    sourceDetailStr,
			sourceID:           sourceID,
			domainID:           domainID,
			sessionFingerprint: sessionFingerprint,
			vec:                embeddings[i],
		})
	}

	tx, err := p.pgconn.Begin()
	if err != nil {
		return fmt.Errorf("add_chunks begin tx: %w", err)
	}
	defer func() {
