			return fmt.Errorf("add_chunks insert: %w", err)
		}
	}
	if err = tx.Commit(); err != nil {
		return fmt.Errorf("add_chunks commit: %w", err)
	}
	return nil
}

func (p *PgVectorBackend) searchHybrid(
	queryVec []float32,
	queryText string,
	where string,
	filterParams []interface{},
	limit int,
	t string,
) ([]pgRow, error) {
	const rrfK = 60
	candidateLimit := limit * 4

	// Vector ranking
	vecParams := make([]interface{}, 0, 2+len(filterParams))
	vecParams = append(vecParams, pgvector.NewVector(queryVec))
	vecParams = append(vecParams, filterParams...)
	vecParams = append(vecParams, pgvector.NewVector(queryVec), candidateLimit)

	rowsVec, err := p.pgconn.Query(
		fmt.Sprintf("SELECT chunk_id, ROW_NUMBER() OVER (ORDER BY embedding <=> $1::vector) AS rank "+
			"FROM %s %s ORDER BY embedding <=> $%d::vector LIMIT $%d",
			t, where, len(filterParams)+2, len(filterParams)+3),
		vecParams...,
	)
	if err != nil {
		return nil, fmt.Errorf("search_hybrid vector query: %w", err)
	}
	defer rowsVec.Close()
	vecRanks := make(map[string]int)
	for rowsVec.Next() {
		var cid string
		var rank int
		if err := rowsVec.Scan(&cid, &rank); err != nil {
			return nil, fmt.Errorf("search_hybrid vec scan: %w", err)
		}
		vecRanks[cid] = rank
	}

	// BM25 ranking
	safeQuery := strings.ReplaceAll(queryText, "'", "''")
	bm25Clause := fmt.Sprintf("fts_vec @@ plainto_tsquery('english', '%s')", safeQuery)
	var bm25Where string
	if where != "" {
		bm25Where = where + " AND " + bm25Clause
	} else {
		bm25Where = "WHERE " + bm25Clause
	}
	bm25Params := make([]interface{}, 0, len(filterParams)+1)
	bm25Params = append(bm25Params, filterParams...)
	bm25Params = append(bm25Params, candidateLimit)

	rowsBM25, err := p.pgconn.Query(
		fmt.Sprintf("SELECT chunk_id, ROW_NUMBER() OVER (ORDER BY ts_rank(fts_vec, plainto_tsquery('english', '%s')) DESC) AS rank "+
			"FROM %s %s LIMIT $%d", safeQuery, t, bm25Where, len(filterParams)+1),
		bm25Params...,
	)
	if err != nil {
		return nil, fmt.Errorf("search_hybrid bm25 query: %w", err)
	}
	defer rowsBM25.Close()
	bm25Ranks := make(map[string]int)
	for rowsBM25.Next() {
		var cid string
		var rank int
		if err := rowsBM25.Scan(&cid, &rank); err != nil {
			return nil, fmt.Errorf("search_hybrid bm25 scan: %w", err)
		}
		bm25Ranks[cid] = rank
	}

	// RRF merge
	allIDs := make(map[string]float64)
	for cid := range vecRanks {
		allIDs[cid] = 0
	}
	for cid := range bm25Ranks {
		allIDs[cid] = 0
	}
	type cidScore struct {
		cid   string
		score float64
	}
	scored := make([]cidScore, 0, len(allIDs))
	for cid := range allIDs {
		vr, ok := vecRanks[cid]
		if !ok {
			vr = candidateLimit + rrfK
		}
		br, ok := bm25Ranks[cid]
		if !ok {
			br = candidateLimit + rrfK
		}
		sc := 1.0/float64(rrfK+vr) + 1.0/float64(rrfK+br)
		scored = append(scored, cidScore{cid, sc})
	}
	sort.Slice(scored, func(i, j int) bool { return scored[i].score > scored[j].score })
	if limit < len(scored) {
		scored = scored[:limit]
	}
