	}

	topIDs := make([]interface{}, len(scored))
	for i, cs := range scored {
		topIDs[i] = cs.cid
	}
	placeholders := make([]string, len(topIDs))
	for i := range topIDs {
		placeholders[i] = fmt.Sprintf("$%d", i+1)
	}
	rowsFinal, err := p.pgconn.Query(
		fmt.Sprintf("SELECT chunk_id, document_name, section, chunk_index, content, breadcrumb, "+
			"chunk_type, source_offset, source_length, source_detail, 0.0::float8 AS similarity "+
			"FROM %s WHERE chunk_id IN (%s)", t, strings.Join(placeholders, ",")),
		topIDs...,
	)
	if err != nil {
		return nil, fmt.Errorf("search_hybrid fetch rows: %w", err)
	}
	defer rowsFinal.Close()
	rowsByID := make(map[string]pgRow)
	for rowsFinal.Next() {
		var r pgRow
		if err := rowsFinal.Scan(&r.chunkID, &r.documentName, &r.section, &r.chunkIndex,
			&r.content, &r.breadcrumb, &r.chunkType, &r.sourceOffset, &r.sourceLength,
			&r.sourceDetail, &r.similarity); err != nil {
			return nil, fmt.Errorf("search_hybrid final scan: %w", err)
		}
		rowsByID[r.chunkID] = r
	}

	result := make([]pgRow, 0, len(scored))
	for _, cs := range scored {
		if r, ok := rowsByID[cs.cid]; ok {
			result = append(result, r)
		}
	}
	return result, nil
}

