        for row in rows:
            cur.execute(
                "INSERT INTO svo_triples (chunk_id, subject_id, verb, object_id, confidence, namespace) "
                "VALUES (%s, %s, %s, %s, %s, %s)",
                row,
            )
    self._pgconn.commit()
    return len(rows)

func (p *PgVectorBackend) StoreSVOTriples(triples []*SVOTriple, namespace *string) (int, error) {
	if len(triples) == 0 {
		return 0, nil
	}
	if err := p.ensureConnection(); err != nil {
		return 0, fmt.Errorf("store_svo_triples ensure connection: %w", err)
	}

	type row struct {
		chunkID    *string
		subjectID  string
		verb       string
		objectID   string
		confidence float64
		ns         *string
	}
	rows := make([]row, 0, len(triples))

	for _, t := range triples {
		ns := namespace
		if ns == nil && t.SourceChunkID != nil && *t.SourceChunkID != "" {
			dbRow := p.pgconn.QueryRow(
				fmt.Sprintf("SELECT namespace FROM %s WHERE chunk_id = $1", p.table),
				*t.SourceChunkID,
			)
			var nsVal *string
			if err := dbRow.Scan(&nsVal); err == nil {
				ns = nsVal
			}
		}
		rows = append(rows, row{
			chunkID:    t.SourceChunkID,
			subjectID:  t.SubjectID,
			verb:       t.Verb,
			objectID:   t.ObjectID,
			confidence: t.Confidence,
			ns:         ns,
		})
	}

	tx, err := p.pgconn.Begin()
	if err != nil {
		return 0, fmt.Errorf("store_svo_triples begin tx: %w", err)
	}
	defer func() {
		if err != nil {
			_ = tx.Rollback()
		}
	}()

	for _, r := range rows {
		if _, err = tx.Exec(
			"INSERT INTO svo_triples (chunk_id, subject_id, verb, object_id, confidence, namespace) "+
				"VALUES ($1, $2, $3, $4, $5, $6)",
			r.chunkID, r.subjectID, r.verb, r.objectID, r.confidence, r.ns,
		); err != nil {
			return 0, fmt.Errorf("store_svo_triples insert: %w", err)
		}
	}
	if err = tx.Commit(); err != nil {
		return 0, fmt.Errorf("store_svo_triples commit: %w", err)
	}
	return len(rows), nil
}

func (s *Store) PromoteDomain(domainName, fromNamespace, toNamespace, targetDBPath string) error {
	conn := s.vector.Conn()

	row := conn.QueryRow(
		"SELECT domain_id FROM domains WHERE namespace_id = ? AND name = ?",
		fromNamespace, domainName,
	)
	var domainID string
	if err := row.Scan(&domainID); err != nil {
		return fmt.Errorf("promote_domain: domain %q not found in namespace %q: %w", domainName, fromNamespace, err)
	}

	_, err := conn.Exec(fmt.Sprintf("ATTACH '%s' AS _promote_target", targetDBPath))
	if err != nil {
		return fmt.Errorf("promote_domain attach: %w", err)
	}
	defer func() {
		_, _ = conn.Exec("DETACH _promote_target")
	}()

	if _, err := conn.Exec(
		"INSERT INTO _promote_target.domains (domain_id, namespace_id, name, description, parent_id, created_at, updated_at) "+
			"SELECT domain_id, ?, name, description, parent_id, created_at, now() FROM domains WHERE domain_id = ? "+
			"ON CONFLICT (domain_id) DO UPDATE SET namespace_id = excluded.namespace_id, updated_at = now()",
		toNamespace, domainID,
	); err != nil {
		return fmt.Errorf("promote_domain copy domains: %w", err)
	}

	if _, err := conn.Exec(
		"INSERT INTO _promote_target.embeddings (chunk_id, document_name, section, chunk_index, content, breadcrumb, "+
			"chunk_type, source_offset, source_length, namespace, embedding, source_detail, source_id, domain_id, session_fingerprint) "+
			"SELECT chunk_id, document_name, section, chunk_index, content, breadcrumb, chunk_type, source_offset, source_length, ?, "+
			"embedding, source_detail, source_id, domain_id, session_fingerprint FROM embeddings WHERE domain_id = ? ON CONFLICT (chunk_id) DO NOTHING",
		toNamespace, domainID,
	); err != nil {
		return fmt.Errorf("promote_domain copy embeddings: %w", err)
	}

	if _, err := conn.Exec(
		"INSERT INTO _promote_target.svo_triples (chunk_id, subject_id, verb, object_id, confidence, namespace) "+
			"SELECT chunk_id, subject_id, verb, object_id, confidence, ? FROM svo_triples "+
			"WHERE chunk_id IN (SELECT chunk_id FROM embeddings WHERE domain_id = ?) ON CONFLICT DO NOTHING",
		toNamespace, domainID,
	); err != nil {
		return fmt.Errorf("promote_domain copy svo_triples: %w", err)
	}

	if err := s.DeleteDomain(domainID); err != nil {
		return fmt.Errorf("promote_domain delete_domain: %w", err)
	}
	if _, err := conn.Exec("DELETE FROM domains WHERE domain_id = ?", domainID); err != nil {
		return fmt.Errorf("promote_domain delete domain row: %w", err)
	}
	return nil
}

