def __init__(
    self,
    db_path: str | Path,
    read_only: bool = False,
    config: dict | None = None,
    init_sql: list[str] | None = None,
):
    if not _DUCKDB_AVAILABLE:
        raise ImportError(
            "duckdb is required for storage. Install it with: pip install chonk[storage]"
        )
    self._db_path = str(db_path)
    self._read_only = read_only
    self._config = config or {}
    self._closed = False
    self._lock = threading.RLock()
    self._init_sql = init_sql or []
    self._init_lock = threading.Lock()

    last_err = None
    for attempt in range(5):
        try:
            self._shared_conn = duckdb.connect(
                self._db_path,
                read_only=self._read_only,
                config=self._config,
            )
            last_err = None
            break
        except duckdb.IOException as e:
            if "Could not set lock" in str(e) and attempt < 4:
                last_err = e
                _try_kill_orphan_lock_holder(str(e))
                logger.warning(f"DuckDB lock conflict, retrying in {attempt + 1}s...")
                time.sleep(attempt + 1)
            else:
                raise
    if last_err is not None:
        raise last_err

    _all_pools.add(self)

    locked = _LockedConnection(self._shared_conn, self._lock)
    for sql in self._init_sql:
        try:
            locked.execute(sql).fetchall()
        except Exception as e:
            logger.debug(f"Init SQL failed (may be expected): {e}")

func NewThreadLocalDuckDB(dbPath string, readOnly bool, config map[string]string, initSQL []string) (*ThreadLocalDuckDB, error) {
	db := &ThreadLocalDuckDB{
		dbPath:   dbPath,
		readOnly: readOnly,
		config:   config,
		initSQL:  initSQL,
	}
	if db.config == nil {
		db.config = make(map[string]string)
	}
	if db.initSQL == nil {
		db.initSQL = []string{}
	}

	var lastErr error
	for attempt := 0; attempt < 5; attempt++ {
		conn, err := duckdb.Open(dbPath)
		if err != nil {
			if strings.Contains(err.Error(), "Could not set lock") && attempt < 4 {
				lastErr = err
				tryKillOrphanLockHolder(err.Error())
				log.Printf("DuckDB lock conflict, retrying in %ds...", attempt+1)
				time.Sleep(time.Duration(attempt+1) * time.Second)
				continue
			}
			return nil, fmt.Errorf("duckdb open %q: %w", dbPath, err)
		}
		db.sharedConn = conn
		lastErr = nil
		break
	}
	if lastErr != nil {
		return nil, fmt.Errorf("duckdb open after retries: %w", lastErr)
	}

	allPoolsMu.Lock()
	allPools = append(allPools, db)
	allPoolsMu.Unlock()

	for _, sql := range db.initSQL {
		if _, err := db.sharedConn.Exec(sql); err != nil {
			log.Printf("Init SQL failed (may be expected): %v", err)
		}
	}
	return db, nil
}

func (p *PgVectorBackend) Search(
	queryEmbedding []float32,
	limit int,
	queryText *string,
	includeBreadcrumbs bool,
	namespaces []string,
	chunkTypes []string,
	domainIDs []string,
	sessionFingerprint *string,
) ([]SearchResult, error) {
	if err := p.ensureConnection(); err != nil {
		return nil, fmt.Errorf("search ensure connection: %w", err)
	}

	t := p.table
	var clauses []string
	var filterParams []interface{}
	paramIdx := 2 // $1 reserved for query vector

	if len(namespaces) > 0 {
		clauses = append(clauses, fmt.Sprintf("namespace = ANY($%d)", paramIdx))
		filterParams = append(filterParams, pq.Array(namespaces))
		paramIdx++
	}
	if len(chunkTypes) > 0 {
		clauses = append(clauses, fmt.Sprintf("chunk_type = ANY($%d)", paramIdx))
		filterParams = append(filterParams, pq.Array(chunkTypes))
		paramIdx++
	}
	if len(domainIDs) > 0 {
		clauses = append(clauses, fmt.Sprintf("domain_id = ANY($%d)", paramIdx))
		filterParams = append(filterParams, pq.Array(domainIDs))
		paramIdx++
	}
	if sessionFingerprint != nil {
		clauses = append(clauses, fmt.Sprintf("session_fingerprint = $%d", paramIdx))
		filterParams = append(filterParams, *sessionFingerprint)
		paramIdx++
	}

	where := ""
	if len(clauses) > 0 {
		where = "WHERE " + strings.Join(clauses, " AND ")
	}

	var pgRows []pgRow
	if queryText != nil {
		var err error
		pgRows, err = p.searchHybrid(queryEmbedding, *queryText, where, filterParams, limit, t)
		if err != nil {
			return nil, fmt.Errorf("search hybrid: %w", err)
		}
	} else {
		vecParam := pgvector.NewVector(queryEmbedding)
		allParams := make([]interface{}, 0, 2+len(filterParams))
		allParams = append(allParams, vecParam)
		allParams = append(allParams, filterParams...)
		allParams = append(allParams, vecParam, limit)
		rows, err := p.pgconn.Query(
			fmt.Sprintf(
				"SELECT chunk_id, document_name, section, chunk_index, content, breadcrumb, "+
					"chunk_type, source_offset, source_length, source_detail, "+
					"1.0 - (embedding <=> $1::vector) AS similarity FROM %s %s "+
					"ORDER BY embedding <=> $%d::vector LIMIT $%d",
				t, where, len(filterParams)+2, len(filterParams)+3),
			allParams...,
		)
		if err != nil {
			return nil, fmt.Errorf("search vector query: %w", err)
		}
		defer rows.Close()
		for rows.Next() {
			var r pgRow
			if err := rows.Scan(&r.chunkID, &r.documentName, &r.section, &r.chunkIndex,
				&r.content, &r.breadcrumb, &r.chunkType, &r.sourceOffset, &r.sourceLength,
				&r.sourceDetail, &r.similarity); err != nil {
				return nil, fmt.Errorf("search scan: %w", err)
			}
			pgRows = append(pgRows, r)
		}
	}

	results := make([]SearchResult, 0, len(pgRows))
	for _, row := range pgRows {
		displayed := row.content
		if includeBreadcrumbs && row.breadcrumb != nil && *row.breadcrumb != "" {
			displayed = fmt.Sprintf("%s\n\n%s", *row.breadcrumb, row.content)
		}
		chunkType := row.chunkType
		if chunkType == "" {
			chunkType = "document"
		}
		var sourceDetail interface{}
		if row.sourceDetail != nil && *row.sourceDetail != "" {
			_ = json.Unmarshal([]byte(*row.sourceDetail), &sourceDetail)
		}
		chunk := &DocumentChunk{
			DocumentName: row.documentName,
			Content:      displayed,
			Section:      deserializeSection(row.section),
			ChunkIndex:   row.chunkIndex,
			SourceOffset: row.sourceOffset,
			SourceLength: row.sourceLength,
			Breadcrumb:   row.breadcrumb,
			ChunkType:    chunkType,
			SourceDetail: sourceDetail,
		}
		results = append(results, SearchResult{ChunkID: row.chunkID, Score: row.similarity, Chunk: chunk})
	}
	return results, nil
}
